def main():
    import argparse
    parser = argparse.ArgumentParser(
        description="MK Planner — decompose complex NL into executable steps")
    parser.add_argument("request", help="Natural-language request to plan")
    parser.add_argument("--execute", "-e", action="store_true",
                        help="Execute the plan after decomposing")
    parser.add_argument("--no-llm", action="store_true",
                        help="Disable LLM fallback (deterministic only)")
    parser.add_argument("--json", action="store_true",
                        help="Output plan as JSON")
    args = parser.parse_args()

    planner = Planner(use_llm=not args.no_llm)
    plan = planner.plan(args.request)

    if args.json:
        print(json.dumps({
            "request": plan.request,
            "steps": plan.steps,
            "source": plan.source,
            "notes": plan.notes,
        }, indent=2))
    else:
        print(f"Source: {plan.source}")
        if plan.steps:
            for i, step in enumerate(plan.steps):
                print(f"  {i+1}. {step}")
        if plan.extra_nodes:
            for node in plan.extra_nodes:
                glob = getattr(node, 'glob_pattern', '?')
                n_body = len(getattr(node, 'body_template', ()))
                print(f"  FOR each file in {glob}: {n_body} body ops")
        if args.execute:
            print("---")
            output = planner.plan_and_execute(args.request)
            if output:
                print(output)

    if args.execute and not plan.steps and not plan.extra_nodes:
        print("(empty plan)")


if __name__ == "__main__":
    main()

